// 1. Accedemos al texto generado por Gemini
const rawText = $json.content.parts[0].text;

// 2. Parseamos el string a JSON real
let parsed;

try {
  parsed = JSON.parse(rawText);
} catch (error) {
  throw new Error("Error parseando JSON: " + error.message);
}

// 3. Convertimos al formato que n8n espera (array de items)
return parsed.map(item => ({
  json: {
    text: item.text,
    source: item.source,
    chunk_index: item.chunk_index,
    chunk_id: item.chunk_id
  }
}));

// Datos del archivo (vienen del nodo Edit Fields)
const fileData = $items("Edit Fields")[0].json;

// Datos principales (los registros)
const data = items.map(i => i.json);

// Fuente (podés cambiarlo si querés)
const source = fileData.fileName || "unknown";

// Transformación
return data.map((item, index) => {

  // Convertimos el objeto a texto clave:valor
  const text = Object.entries(item)
    .map(([key, value]) => `${key}: ${value}`)
    .join(", ");

  return {
    json: {
      text,
      source,
      chunk_index: index,
      chunk_id: `${source}_${index}`
    }
  };
});

const globalData = $getWorkflowStaticData('global');

// Inicializar si no existe
if (!globalData.retries) {
  globalData.retries = 0;
}

// Incrementar
globalData.retries += 1;

return items.map(item => ({
  json: {
    ...item.json,
    retries: globalData.retries
  }
}));

