// ===============================
// 1. EMBEDDING DE RESPUESTA
// ===============================
const responseEmbedding = $input.first().json.embedding.values;

if (!responseEmbedding) {
  throw new Error("No se encontró el embedding de la respuesta");
}

// ===============================
// 2. EMBEDDINGS DE FRAGMENTOS (HTTP Request3)
// ===============================
const fragmentItems = $items("HTTP Request3", 0, 0);

// extraer embeddings
const fragmentEmbeddings = fragmentItems
  .map(item => item.json.embedding?.values)
  .filter(e => e && Array.isArray(e));

if (fragmentEmbeddings.length === 0) {
  throw new Error("No hay embeddings de fragmentos");
}

// ===============================
// 3. COSINE SIMILARITY
// ===============================
function cosineSimilarity(a, b) {
  if (a.length !== b.length) return 0;

  let dot = 0;
  let normA = 0;
  let normB = 0;

  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }

  normA = Math.sqrt(normA);
  normB = Math.sqrt(normB);

  if (normA === 0 || normB === 0) return 0;

  return dot / (normA * normB);
}

// ===============================
// 4. CALCULAR SCORES
// ===============================
const scores = fragmentEmbeddings.map(fragment => {
  const sim = cosineSimilarity(responseEmbedding, fragment);

  // normalizar de [-1,1] → [0,1]
  const normalized = (sim + 1) / 2;

  return normalized;
});

// ===============================
// 5. MÉTRICAS
// ===============================
const avgScore =
  scores.reduce((acc, val) => acc + val, 0) / scores.length;

const maxScore = Math.max(...scores);

// ===============================
// 6. OUTPUT
// ===============================
return [
  {
    json: {
      score: avgScore,        // score global
      maxScore: maxScore,     // mejor match
      scores: scores,         // detalle por fragmento
      fragments: scores.length
    }
  }
];

